package main

import (
	"log"
	"os"

	"github.com/gin-gonic/gin"
	"github.com/taskflow/api/internal/api"
	"github.com/taskflow/api/internal/store"
)

func main() {
	db, err := store.Connect(os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	r := gin.Default()
	api.RegisterRoutes(r, db)
	r.Run(":8080")
}

CREATE TABLE projects (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT,
  owner_id UUID NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE tasks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  description TEXT,
  status TEXT NOT NULL DEFAULT 'todo' CHECK (status IN ('todo', 'in_progress', 'review', 'done')),
  assignee_id UUID,
  priority INTEGER DEFAULT 0,
  due_date DATE,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX idx_tasks_project ON tasks(project_id);
CREATE INDEX idx_tasks_status ON tasks(status);
CREATE INDEX idx_tasks_assignee ON tasks(assignee_id);

package store

import (
	"context"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
)

var validTransitions = map[string][]string{
	"todo":        {"in_progress"},
	"in_progress": {"review", "todo"},
	"review":      {"done", "in_progress"},
	"done":        {},
}

func ValidateTransition(from, to string) error {
	allowed, ok := validTransitions[from]
	if !ok {
		return fmt.Errorf("unknown status: %s", from)
	}
	for _, s := range allowed {
		if s == to {
			return nil
		}
	}
	return fmt.Errorf("invalid transition: %s -> %s", from, to)
}

type TaskStore struct {
	pool *pgxpool.Pool
}

func (s *TaskStore) UpdateStatus(ctx context.Context, taskID, newStatus string) error {
	var current string
	err := s.pool.QueryRow(ctx, "SELECT status FROM tasks WHERE id = $1", taskID).Scan(&current)
	if err != nil {
		return err
	}
	if err := ValidateTransition(current, newStatus); err != nil {
		return err
	}
	_, err = s.pool.Exec(ctx, "UPDATE tasks SET status = $1, updated_at = now() WHERE id = $2", newStatus, taskID)
	return err
}

package auth

import (
	"net/http"
	"strings"

	"github.com/gin-gonic/gin"
	"github.com/lestrrat-go/jwx/v2/jwk"
	"github.com/lestrrat-go/jwx/v2/jwt"
)

type Claims struct {
	UserID string
	Role   string
}

func JWTMiddleware(jwksURL string) gin.HandlerFunc {
	cache := jwk.NewCache(nil)
	cache.Register(jwksURL)

	return func(c *gin.Context) {
		token := extractToken(c)
		if token == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing token"})
			return
		}

		keyset, err := cache.Get(c, jwksURL)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusInternalServerError, gin.H{"error": "jwks fetch failed"})
			return
		}

		parsed, err := jwt.Parse([]byte(token), jwt.WithKeySet(keyset), jwt.WithValidate(true))
		if err != nil {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		claims := Claims{
			UserID: parsed.Subject(),
			Role:   getStringClaim(parsed, "role"),
		}
		c.Set("user", claims)
		c.Next()
	}
}

func extractToken(c *gin.Context) string {
	auth := c.GetHeader("Authorization")
	if strings.HasPrefix(auth, "Bearer ") {
		return strings.TrimPrefix(auth, "Bearer ")
	}
	return c.Query("token")
}

func getStringClaim(t jwt.Token, key string) string {
	v, ok := t.Get(key)
	if !ok {
		return ""
	}
	s, _ := v.(string)
	return s
}

package ws

import (
	"encoding/json"
	"sync"

	"github.com/gorilla/websocket"
)

type StatusChange struct {
	TaskID    string `json:"task_id"`
	ProjectID string `json:"project_id"`
	OldStatus string `json:"old_status"`
	NewStatus string `json:"new_status"`
	ChangedBy string `json:"changed_by"`
}

type Hub struct {
	mu    sync.RWMutex
	conns map[string]map[*websocket.Conn]bool // projectID -> connections
}

func NewHub() *Hub {
	return &Hub{conns: make(map[string]map[*websocket.Conn]bool)}
}

func (h *Hub) Subscribe(projectID string, conn *websocket.Conn) {
	h.mu.Lock()
	defer h.mu.Unlock()
	if h.conns[projectID] == nil {
		h.conns[projectID] = make(map[*websocket.Conn]bool)
	}
	h.conns[projectID][conn] = true
}

func (h *Hub) Unsubscribe(projectID string, conn *websocket.Conn) {
	h.mu.Lock()
	defer h.mu.Unlock()
	delete(h.conns[projectID], conn)
}

func (h *Hub) Broadcast(change StatusChange) {
	h.mu.RLock()
	defer h.mu.RUnlock()
	msg, _ := json.Marshal(change)
	for conn := range h.conns[change.ProjectID] {
		conn.WriteMessage(websocket.TextMessage, msg)
	}
}
